但我睇html果part同原本html syntax唔同<br />
<pre><code data-type="">- var v = ['top', 'bottom'];
- var p = v.length;
- var h = ['left', 'right'];
- var q = h.length;
- var dims = ['x', 'y'];
- var n = dims.length;
- var vals = '';

section
 .container
  .iso
   - for(var i = 0; i &lt; p; i++)
    - for(var j = 0; j &lt; q; j++)
     - for(var k = 0; k &lt; n; k++) {
      - var sf = ((1 - k)*j || k*i) ? -1 : 1
      - var val = 38 + Math.round(9*Math.random());
      - vals += `--r${dims[k]}${i}${j}: ${val}%;`
      .wrap(style=`--v: ${i}; --h: ${j}; --ax: ${k}; --val: ${val}; --sf: ${sf}`)
       input(type='range' value=val id=`r${dims[k]}${i}${j}`)
       label(for=`r${dims[k]}${i}${j}`)
        span #{v[i]} #{h[j]}
        var r#{dims[k]}
        output
     - }
  #blob(style=vals)
pre#code</code></pre><br />
